import json as _j, pathlib as _p
il = _j.loads(_p.Path(str(ROOT / 'data/interlinear/jeremiah.json')).read_text())
for ch in ['31', '32']:
    have = set(comm.get(ch, {}).keys())
    need = set(il.get(ch, {}).keys())
    missing = need - have
    print(f"  ch {ch}: {len(need)-len(missing)}/{len(need)} verses present, {len(missing)} missing: {sorted(missing,key=int) if missing else 'none'}")
